// server/apis/public/ping.api.ts → GET /api/public/ping
import { defineApi } from "../../howl.config.ts";
import { z } from "zod";

export default defineApi({
  name: "Ping",
  directory: "public",
  method: "GET",
  roles: [],              // [] = public, no auth
  responses: {
    200: z.object({ message: z.string() }),
  },
  handler: (ctx) => ({
    statusCode: 200,
    message: `pong — ${new Date().toISOString()}`,
  }),
});

