export default defineApi({
  name: "Create User",
  method: "POST",
  requestBody: z.object({
    email: z.string().email(),
    name: z.string().min(2),
    password: z.string().min(8),
  }),
  handler: (ctx) => {
    const { email, name } = ctx.req.body; // fully typed
    return { statusCode: 201, id: crypto.randomUUID(), email, name };
  },
});

